    const navigate = useNavigate();

    React.useEffect(() => {
        if(!user && navigate){
            navigate("/")
        }
    }, [user,navigate])
    return (
        <div className = "dashboard">
            <div className = 'ticket'>

            </div>
        </div>
    )
}

export default Dashboard
